# Server IP address
host = escolher_host

# IP address processing for RakNet protocol
ip = socket.gethostbyname(host)
# Her IP oktetini tersine çevirip 2 hex haneli olarak formatlama
# Örneğin, 0x0 yerine '00', 0x1 yerine '01'
ip_in_bytes = "".join([hex(~int(octet) & 0xff)[2:].zfill(2) for octet in ip.split(".")])

# IP ve portu hex formatında (bazı paketler için)
ip_and_port_in_hex = (ip + ":" + str(port)).encode().hex()

# Text colors for console output
class Colors:
    Black = "\033[30m"
    Red = "\033[31m"
    Green = "\033[32m"
    Orange = "\033[33m"
    Blue = "\033[34m"
    Purple = "\033[35m"
    Cyan = "\033[36m"
    LightGrey = "\033[37m"
    DarkGrey = "\033[90m"
    LightRed = "\033[91m"
    Yellow = "\033[93m"
    LightBlue = "\033[94m"
    Pink = "\033[95m"
    LightCyan = "\033[96m"
    Reset = "\033[0m"

# guid (UUID) generation for game identification
class guid:
    guid1 = str(uuid.uuid1()).lower().split("-")
    guid4 = str(uuid.uuid4()).lower().split("-")

# RakNet protocol specific packets
class RakNet:
    Magic = "00ffff00fefefefefdfdfdfd12345678"
    Creq1 = "05" + Magic + "07" + "0" * 2892
    
    # Portun RakNet paketlerinde tutarlı 2 bayt (4 hex hane) olması sağlanır.
    # Portun 2 bayta sığdığı varsayılır (0-65535).
    port_hex_2bytes = hex(port)[2:].zfill(4)
    Creq2 = "07" + Magic + "04" + ip_in_bytes + port_hex_2bytes + "05b8" + "0" * 8 + guid.guid4[2] + guid.guid4[1]

# Minecraft PE 0.14.0 game-specific packets
class GamePackets:
    # Ready paketi için de tutarlı formatlanmış port hex dizesi kullanılır.
    Ready = "840100006002f0010000000000001304" + ip_in_bytes + RakNet.port_hex_2bytes + "0480fffffe4abc04ffffffff000004ffffffff000004ffffffff000004ffffffff000004ffffffff000004ffffffff000004ffffffff000004ffffffff000004ffffffff0000000000000000"

# Dictionary to hold active socket objects
